import { styled } from 'styled-components';

import { WrapperProps } from './IconButton.types';

export const Wrapper = styled.button<WrapperProps>`
  --icon-width: ${({ theme, $size }) => theme.dimension.icon[$size].width}px;
  --button-width: ${({ theme, width }) =>
    width || theme.dimension.minTouchArea}px;
  display: flex;
  width: var(--button-width);
  height: var(--button-width);
  box-sizing: border-box;
  align-items: center;
  justify-content: center;
  color: ${(props) => props.theme.color.actionBlack.base};
  transition: ${({ theme }) => theme.transition.base};
  transition-property: color, background-color;

  &:hover,
  &:active,
  &:focus-visible {
    color: ${({ theme }) => theme.color.actionBlack.alt};
    outline: none;
  }

  &[disabled] {
    color: ${({ theme }) => theme.color.semiotic.disabled};
  }
`;

export const CosyWrapper = styled(Wrapper)`
  --padding: calc((var(--button-width) - var(--icon-width)) / 2);
  padding: var(--padding);
  margin: calc(var(--padding) * -1);
`;

export default Wrapper;
