import { FC } from 'react';

import { Icon } from '#components/Icon';

import { Wrapper as BaseWrapper, CosyWrapper } from './IconButton.styles';
import { IconButtonProps } from './IconButton.types';

const IconButton: FC<IconButtonProps> = ({
  title,
  svg,
  size = 'base',
  width,
  isCosy = false,
  isDisabled = false,
  ...rest
}) => {
  const Wrapper = isCosy ? CosyWrapper : BaseWrapper;

  return (
    <Wrapper
      {...rest}
      title={title}
      $size={size}
      width={width}
      disabled={isDisabled}
    >
      <Icon size={size} svg={svg} />
    </Wrapper>
  );
};

export default IconButton;
